#!/usr/bin/env python
"""
Bootstrap: PFAS-Free Multi-Layer Coating Design
  Physics: Young, Cassie-Baxter, Wenzel, Laplace, Bragg, Fick WVTR
  Layers: primer, omniphobic (re-entrant), structural color, breathability, durability
  Substrates: textile, rigid, film (8 pre-defined)
  Key: oil repulsion WITHOUT fluorine via Tuteja re-entrant geometry
  36 tests, 563 total, zero regression
Usage: python bootstrap_pfas_coating.py
"""
import base64, os, sys
if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)
FILES = {
    'core/pfas_free_coating.py': '',
    'tests/test_pfas_free_coating.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f: f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")
print("Done. Run: python -m pytest tests/test_pfas_free_coating.py -v")